def trimmed_mean(nums):
    if not nums or len(nums) <= 1:
        return None
    sorted_nums = sorted(nums)
    min_count, max_count = nums.count(min(sorted_nums)), nums.count(max(sorted_nums))
    if min_count > 1 or max_count > 1:
        raise ValueError("Input list should contain unique minimum and maximum values")
    median_index = len(nums) // 2
    if len(nums) % 2 == 0:
        mid1, mid2 = sorted_nums[median_index - 1], sorted_nums[median_index]
    else:
        mid = sorted_nums[median_index]
    trimmed_sum = sum(sorted_nums) - (min(mid, mid1) if min_count == 1 else max(mid, mid2)) - (max(mid, mid1) if max_count == 1 else min(mid, mid2))
    return trimmed_sum / (len(nums) - 2 if len(nums) > 2 else 0)
